import { Hono } from 'hono';
import { Context } from 'hono/types';

const app = new Hono();

app.get('/list-tasks', async (c: Context) => {
  const limit = parseInt(c.req.query('limit')) || 10;
  const offset = parseInt(c.req.query('offset')) || 0;

  // Assuming you have a function to fetch tasks for the current user's team
  const tasks = await getTasksForCurrentTeam(limit, offset);

  return c.json(tasks);
});

async function getTasksForCurrentTeam(limit: number, offset: number): Promise<any[]> {
  // Replace this with your actual implementation to fetch tasks from the database or any other data source
  // For demonstration purposes, let's assume we have a static array of tasks
  const allTasks = [
    { id: 1, title: 'Task 1', description: 'Description for Task 1' },
    { id: 2, title: 'Task 2', description: 'Description for Task 2' },
    // ... more tasks
  ];

  return allTasks.slice(offset, offset + limit);
}

export default app;

